# New models for logs and metrics (original_spec)
class LogSearchRequest(BaseModel):
    """Request model for searching runtime logs."""

    from_: Optional[int] = Field(None, alias="from")
    limit: Optional[int] = None
    from_timestamp: Optional[str] = Field(None, alias="fromTimestamp")
    to_timestamp: Optional[str] = Field(None, alias="toTimestamp")
    query: Optional[str] = None

    class Config:
        populate_by_name = True


class LogRecord(BaseModel):
    """Single log record."""

    timestamp: Optional[str] = None
    content: Optional[str] = None


class LogSearchResult(BaseModel):
    """Result of log search."""

    total_count: Optional[int] = Field(None, alias="totalCount")
    logs: Optional[List[LogRecord]] = None

    class Config:
        populate_by_name = True


class MetricDataPointDouble(BaseModel):
    """Metric data point with float value."""

    timestamp: Optional[str] = None
