class AgentRuntimeEndpointMetrics(BaseModel):
    """Metrics for an agent runtime endpoint."""

    cpu_cores_usage: Optional[List[MetricDataPointDouble]] = Field(None, alias="cpuCoresUsage")
    memory_bytes_usage: Optional[List[MetricDataPointLong]] = Field(None, alias="memoryBytesUsage")

    class Config:
        populate_by_name = True


